<body>

<div id="container">
    <canvas id="sand" width="100" height="100"></canvas>

    <div class="controls">
        <button id="mat-sand" class="mat-sand selected">Sand</button>
        <button id="mat-water" class="mat-water">Water</button>
        <button id="mat-acid" class="mat-acid">Acid</button>
        <button id="mat-wall" class="mat-wall">Wall</button>
        <button id="mat-empty" class="mat-empty">Eraser</button>
        <div style="width: 100%; height: 0;"></div> <!-- Spacer -->
        <button id="clear">Clear All</button>
    </div>
</div>

<script>
(function() {
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false });
    const w = 100;
    const h = 100;

    // Material Constants
    const EMPTY = 0;
    const SAND = 1;
    const WATER = 2;
    const WALL = 3;
    const ACID = 4;

    const materials = ["empty", "sand", "water", "wall", "acid"];
    const colors = ["#000000", "#d2b48c", "#3498db", "#7f8c8d", "#2ecc71"];
    const matMap = { "empty": 0, "sand": 1, "water": 2, "wall": 3, "acid": 4 };

    // Simulation State
    let grid = new Uint8Array(w * h);
    let nextGrid = new Uint8Array(w * h); // Not used for single-buffer logic but good to have
    let moved = new Uint8Array(w * h);

    // API Implementation
    window.sim = {
        w, h,
        get: (x, y) => {
            if (x < 0 || x >= w || y < 0 || y >= h) return "empty";
            return materials[grid[y * w + x]];
        },
        set: (x, y, material) => {
            if (x >= 0 && x < w && y >= 0 && y < h) {
                grid[y * w + x] = matMap[material];
            }
        },
        clear: () => {
            grid.fill(EMPTY);
        },
        tick: (n) => {
            for (let i = 0; i < n; i++) {
                _step();
            }
        }
    };

    function _step() {
        moved.fill(0);

        // 1. Dissolution Phase (Acid dissolves sand/wall)
        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const idx = y * w + x;
                if (grid[idx] === ACID) {
                    // Check neighbors: below and sides
                    const targets = [[x, y+1], [x-1, y], [x+1, y]];
                    for (let [tx, ty] of targets) {
                        if (tx >= 0 && tx < w && ty >= 0 && ty < h) {
                            const tidx = ty * w + tx;
                            if (grid[tidx] === SAND || grid[tidx] === WALL) {
                                grid[tidx] = EMPTY;
                            }
                        }
                    }
                }
            }
        }

        // 2. Movement Phase (Bottom-up to prevent teleporting)
        for (let y = h - 2; y >= 0; y--) {
            for (let x = 0; x < w; x++) {
                const idx = y * w + x;
                if (moved[idx] || grid[idx] === WALL) continue;

                const mat = grid[idx];
                if (mat === SAND) {
                    // Try Down
                    let downIdx = (y + 1) * w + x;
                    let targetMat = grid[downIdx];
                    if (targetMat === EMPTY || targetMat === WATER || targetMat === ACID) {
                        grid[downIdx] = SAND;
                        grid[idx] = (targetMat === EMPTY) ? EMPTY : targetMat;
                        moved[downIdx] = 1;
                        if (targetMat !== EMPTY) moved[idx] = 1; // Swapped particle is now at idx
                    } else {
                        // Try Diagonals
                        let diagL = y * w + (x - 1); // This logic is actually (x-1, y+1)
                        // Correcting diagonal check:
                        const diagonals = [[x - 1, y + 1], [x + 1, y + 1]];
                        for (let [dx, dy] of diagonals) {
                            if (dx >= 0 && dx < w && dy < h) {
                                let dIdx = dy * w + dx;
                                if (grid[dIdx] === EMPTY) {
                                    grid[dIdx] = SAND;
                                    grid[idx] = EMPTY;
                                    moved[dIdx] = 1;
                                    break;
                                }
                            }
                        }
                    }
                } else if (mat === WATER || mat === ACID) {
                    // Try Down
                    let downIdx = (y + 1) * w + x;
                    if (grid[downIdx] === EMPTY) {
                        grid[downIdx] = mat;
                        grid[idx] = EMPTY;
                        moved[downIdx] = 1;
                    } else {
                        // Try Horizontal Spread
                        const sides = [[x - 1, y], [x + 1, y]];
                        for (let [sx, sy] of sides) {
                            if (sx >= 0 && sx < w && sy >= 0 && sy < h) {
                                let sIdx = sy * w + sx;
                                if (grid[sIdx] === EMPTY && !moved[sIdx]) {
                                    grid[sIdx] = mat;
                                    grid[idx] = EMPTY;
                                    moved[sIdx] = 1;
                                    break;
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Rendering
    function render() {
        const imgData = ctx.createImageData(w, h);
        for (let i = 0; i < grid.length; i++) {
            const color = colors[grid[i]];
            const r = parseInt(color.slice(1, 3), 16);
            const g = parseInt(color.substring(3, 5), 16);
            const b = parseInt(color.substring(5, 7), 16);
            const p = i * 4;
            imgData.data[p] = r;
            imgData.data[p+1] = g;
            imgData.data[p+2] = b;
            imgData.data[p+3] = 255;
        }
        ctx.putImageData(imgData, 0, 0);
    }

    function loop() {
        window.sim.tick(1);
        render();
        requestAnimationFrame(loop);
    }

    // UI Interaction
    let selectedMat = EMPTY;
    const buttons = document.querySelectorAll('.controls button');
    buttons.forEach(btn => {
        btn.addEventListener('click', () => {
            if (btn.id === 'clear') {
                window.sim.clear();
                return;
            }
            // Handle material selection
            const id = btn.id.replace('mat-', '');
            selectedMat = matMap[id];
            buttons.forEach(b => b.classList.remove('selected'));
            btn.classList.add('selected');
        });
    });

    document.getElementById('clear').onclick = () => window.sim.clear();

    // Mouse Painting
    let isDrawing = false;
    const getMousePos = (e) => {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width / rect.width;
        const scaleY = canvas.height / rect.height;
        return {
            x: Math.floor((e.clientX - rect.left) * scaleX),
            y: Math.floor((e.clientY - rect.top) * scaleY)
        };
    };

    const paint = (e) => {
        if (!isDrawing) return;
        const pos = getMousePos(e);
        // Brush size 2x2
        for(let dy = -1; dy <= 1; dy++) {
            for(let dx = -1; dx <= 1; dx++) {
                const nx = pos.x + dx, ny = pos.y + dy;
                if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
                    // If erasing, only replace non-empty/non-wall? No, just set to empty.
                    window.sim.set(nx, ny, materials[selectedMat]);
                }
            }
        }
    };

    canvas.addEventListener('mousedown', (e) => { isDrawing = true; paint(e); });
    window.addEventListener('mousemove', paint);
    window.addEventListener('mouseup', () => isDrawing = false);

    // Start simulation
    loop();

})();
</script>
</body>
</html>
